// Generate deep research queries for each contact
const contacts = $input.all();
const allQueries = [];

for (const item of contacts) {
  const c = item.json;
  const name = c.full_name || '';
  const company = c.company_name || '';
  const title = c.job_title || '';

  // Research dimensions
  const queries = [
    // Professional background
    {
      query: `"${name}" "${company}" LinkedIn`,
      dimension: 'professional_background',
      contact: c
    },
    // Podcast/interview appearances
    {
      query: `"${name}" (podcast OR interview OR webinar OR panel) coffee OR procurement OR sourcing`,
      dimension: 'media_appearances',
      contact: c
    },
    // LinkedIn posts and activity
    {
      query: `site:linkedin.com "${name}" (post OR article OR shared)`,
      dimension: 'linkedin_activity',
      contact: c
    },
    // Company news and developments
    {
      query: `"${company}" (expansion OR launch OR partnership OR acquisition OR hiring) 2025 OR 2026`,
      dimension: 'company_news',
      contact: c
    },
    // Industry involvement
    {
      query: `"${name}" (conference OR summit OR award OR speaker OR judge) coffee OR food OR beverage`,
      dimension: 'industry_involvement',
      contact: c
    },
    // Pain points / challenges
    {
      query: `"${company}" (challenge OR struggle OR looking for OR seeking) coffee OR supply OR sourcing`,
      dimension: 'pain_signals',
      contact: c
    }
  ];

  allQueries.push(...queries);
}

return allQueries.map(q => ({ json: q }));

// Aggregate research findings by contact
const items = $input.all();
const contactResearch = new Map();

for (const item of items) {
  const dimension = item.json.dimension || 'unknown';
  const contact = item.json.contact || {};
  const contactKey = `${contact.full_name}::${contact.company_name}`;
  const webResults = item.json.web?.results || [];

  if (!contactResearch.has(contactKey)) {
    contactResearch.set(contactKey, {
      contact,
      research: {
        professional_background: [],
        media_appearances: [],
        linkedin_activity: [],
        company_news: [],
        industry_involvement: [],
        pain_signals: []
      }
    });
  }

  const entry = contactResearch.get(contactKey);
  const findings = webResults.map(r => ({
    title: r.title || '',
    url: r.url || '',
    snippet: (r.description || '').substring(0, 300)
  })).filter(f => f.title && f.snippet);

  if (entry.research[dimension]) {
    entry.research[dimension].push(...findings);
  }
}

// Format for Claude AI synthesis
const output = [];
for (const [key, data] of contactResearch) {
  output.push({
    json: {
      ...data.contact,
      raw_research: data.research,
      research_query_count: Object.values(data.research).flat().length,
      pipeline_stage: 'research_gathered'
    }
  });
}

return output;

// Prepare Claude prompt for research synthesis
const contacts = $input.all();
const results = [];

for (const item of contacts) {
  const c = item.json;
  const research = c.raw_research || {};

  const prompt = `You are a world-class sales intelligence researcher. Synthesize the following raw research about a prospect into actionable sales intelligence.

PROSPECT:
- Name: ${c.full_name}
- Title: ${c.job_title}
- Company: ${c.company_name}
- LinkedIn: ${c.linkedin_url || 'N/A'}

RAW RESEARCH FINDINGS:

1. Professional Background:
${JSON.stringify(research.professional_background?.slice(0, 5) || [], null, 2)}

2. Media Appearances (podcasts, interviews, etc.):
${JSON.stringify(research.media_appearances?.slice(0, 5) || [], null, 2)}

3. LinkedIn Activity:
${JSON.stringify(research.linkedin_activity?.slice(0, 5) || [], null, 2)}

4. Company News & Developments:
${JSON.stringify(research.company_news?.slice(0, 5) || [], null, 2)}

5. Industry Involvement:
${JSON.stringify(research.industry_involvement?.slice(0, 5) || [], null, 2)}

6. Pain Signals:
${JSON.stringify(research.pain_signals?.slice(0, 5) || [], null, 2)}

SYNTHESIZE INTO:
{
  "personal_hook": "One specific, personal detail that shows you did your homework (podcast they were on, post they wrote, event they spoke at, etc.)",
  "company_trigger": "What's happening at their company that creates a buying window (expansion, new locations, hiring, etc.)",
  "pain_hypothesis": "Based on their role and company context, what procurement pain are they likely experiencing?",
  "connection_angle": "How does our offer (PROBAT P60 roasted coffee from Vietnam, 30-40% lower costs, 40-50 MT/month capacity) connect to their specific situation?",
  "recommended_tone": "Should this email be data-driven, relationship-focused, or industry-insider based on their profile?",
  "ice_breaker": "A natural, non-creepy opening line that references something specific about them",
  "confidence_level": "high/medium/low - based on how much usable research was found"
}

Return ONLY the JSON object, no markdown.`;

  results.push({
    json: {
      ...c,
      synthesis_prompt: prompt
    }
  });
}

return results;

// Parse Claude's research synthesis
const items = $input.all();
const contacts = $('Prepare AI Synthesis').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;
  const contact = contacts[i]?.json || {};
  const content = response.content?.[0]?.text || '';

  let synthesis = {};
  try {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      synthesis = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    synthesis = {
      personal_hook: '',
      company_trigger: '',
      pain_hypothesis: 'General procurement efficiency',
      connection_angle: 'Cost savings through origin-roasted coffee',
      recommended_tone: 'data-driven',
      ice_breaker: '',
      confidence_level: 'low'
    };
  }

  // Remove raw research to keep payload clean
  const { raw_research, synthesis_prompt, ...cleanContact } = contact;

  results.push({
    json: {
      ...cleanContact,
      research_synthesis: synthesis,
      personal_hook: synthesis.personal_hook || '',
      company_trigger: synthesis.company_trigger || '',
      pain_hypothesis: synthesis.pain_hypothesis || '',
      connection_angle: synthesis.connection_angle || '',
      recommended_tone: synthesis.recommended_tone || 'professional',
      ice_breaker: synthesis.ice_breaker || '',
      research_confidence: synthesis.confidence_level || 'low',
      pipeline_stage: 'research_complete',
      researched_at: new Date().toISOString()
    }
  });
}

return results;
